public void insert()
{
    next insert();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {

        str descriptiveKeyCollection = strFmt(
            "ZipCode='%1', CountryRegionId='%2', StateId='%3', CountyId='%4', CityId='%5', DistrictId='%6', StreetNumberMinimum='%7', StreetNumberMaximum='%8', StreetNumberValidity='%9'",
            this.ZipCode,
            this.CountryRegionId,
            this.State,
            this.County,
            this.City,
            this.DistrictName,
            this.FromNum,
            this.ToNum,
            enum2Symbol(enumNum(AllEvenOdd),this.EvenOdd)
        );

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("AddressPostalCodesV2");
        contract.parmOperationType("Insert");

        ETGDMSRevereIntegrationEventClass eventClass =
            ETGDMSRevereIntegrationEventClass::newFromContract(contract);

        eventClass.send();
    }
}

